56	// LoadProfileSnapshot fetches fizeau profiles and models with short-lived,
57	// stale-on-error memoization keyed to the service identity.
58	func LoadProfileSnapshot(ctx context.Context, svc agentlib.FizeauService) (ProfileSnapshot, error) {
59		if svc == nil {
60			return ProfileSnapshot{}, nil
61		}
62		if ctx == nil {
63			ctx = context.Background()
64		}
65		key := profileSnapshotServiceCacheKey(svc)
66		return loadProfileSnapshot(ctx, key, svc)
67	}
