69	// WarmProfileSnapshotForProject starts a non-blocking refresh of the profile
70	// snapshot used by lifecycle hooks. It is intentionally best-effort; callers
71	// should proceed without a DDx-selected profile when no hot snapshot is present.
72	func WarmProfileSnapshotForProject(projectRoot string, svc agentlib.FizeauService, runner AgentRunner) {
73		if runner != nil {
74			return
75		}
76		selectedSvc := svc
77		if selectedSvc == nil {
78			factory := serviceRunFactory
79			if factory == nil {
80				factory = NewServiceFromWorkDir
81			}
82			built, err := factory(projectRoot)
83			if err != nil {
84				return
85			}
86			selectedSvc = built
87		}
88		startProfileSnapshotRefresh(profileSnapshotProjectCacheKey(projectRoot, selectedSvc), selectedSvc)
89	}
