91	func loadProfileSnapshot(ctx context.Context, key string, svc agentlib.FizeauService) (ProfileSnapshot, error) {
92		now := profileSnapshotNow()
93	
94		var last profileSnapshotCacheEntry
95		var hadLast bool
96		if key != "" {
97			profileSnapshotCacheMu.Lock()
98			if entry, ok := profileSnapshotCache[key]; ok && now.Sub(entry.loadedAt) < profileSnapshotCacheWindow {
99				snap := cloneProfileSnapshot(entry.snap)
100				profileSnapshotCacheMu.Unlock()
101				return snap, nil
102			}
103			last, hadLast = profileSnapshotCache[key]
104			profileSnapshotCacheMu.Unlock()
105		}
106	
107		loadCtx, cancel := context.WithTimeout(ctx, profileSnapshotLoadTimeout)
108		defer cancel()
109	
110		profiles, err := svc.ListPolicies(loadCtx)
111		if err != nil {
112			if hadLast {
113				markProfileSnapshotRefreshDone(key, false, ProfileSnapshot{})
114				return cloneProfileSnapshot(last.snap), nil
115			}
116			markProfileSnapshotRefreshDone(key, false, ProfileSnapshot{})
117			return ProfileSnapshot{}, err
118		}
119		models, err := svc.ListModels(loadCtx, agentlib.ModelFilter{})
120		if err != nil {
121			if hadLast {
122				markProfileSnapshotRefreshDone(key, false, ProfileSnapshot{})
123				return cloneProfileSnapshot(last.snap), nil
124			}
125			// Model discovery is advisory for DDx profile selection. Fizeau still
126			// owns concrete routing and candidate filtering at dispatch time, so do
127			// not let a slow/stale model snapshot consume the readiness budget.
128			models = nil
129		}
130	
131		snap := ProfileSnapshot{
132			Profiles: append([]agentlib.PolicyInfo(nil), profiles...),
133			Models:   append([]agentlib.ModelInfo(nil), models...),
134		}
135		if key != "" {
136			profileSnapshotCacheMu.Lock()
137			profileSnapshotCache[key] = profileSnapshotCacheEntry{snap: cloneProfileSnapshot(snap), loadedAt: now}
138			profileSnapshotCacheMu.Unlock()
139		}
140		return snap, nil
141	}
