156	func startProfileSnapshotRefresh(key string, svc agentlib.FizeauService) {
157		if key == "" || svc == nil {
158			return
159		}
160		now := profileSnapshotNow()
161		profileSnapshotCacheMu.Lock()
162		entry := profileSnapshotCache[key]
163		if entry.refreshing && now.Sub(entry.refreshStartedAt) < profileSnapshotRefreshTimeout {
164			profileSnapshotCacheMu.Unlock()
165			return
166		}
167		if !entry.loadedAt.IsZero() && now.Sub(entry.loadedAt) < profileSnapshotRefreshInterval {
168			profileSnapshotCacheMu.Unlock()
169			return
170		}
171		if !entry.lastAttemptAt.IsZero() && now.Sub(entry.lastAttemptAt) < profileSnapshotRefreshRetryAfter {
172			profileSnapshotCacheMu.Unlock()
173			return
174		}
175		entry.refreshing = true
176		entry.refreshStartedAt = now
177		entry.lastAttemptAt = now
178		profileSnapshotCache[key] = entry
179		profileSnapshotCacheMu.Unlock()
180	
181		go func() {
182			ctx, cancel := context.WithTimeout(context.Background(), profileSnapshotRefreshTimeout)
183			defer cancel()
184			snap, err := fetchProfileSnapshot(ctx, svc)
185			if err != nil {
186				markProfileSnapshotRefreshDone(key, false, ProfileSnapshot{})
187				return
188			}
189			markProfileSnapshotRefreshDone(key, true, snap)
190		}()
191	}
