203	func markProfileSnapshotRefreshDone(key string, ok bool, snap ProfileSnapshot) {
204		if key == "" {
205			return
206		}
207		now := profileSnapshotNow()
208		profileSnapshotCacheMu.Lock()
209		entry := profileSnapshotCache[key]
210		entry.refreshing = false
211		if ok {
212			entry.snap = cloneProfileSnapshot(snap)
213			entry.loadedAt = now
214		}
215		profileSnapshotCache[key] = entry
216		profileSnapshotCacheMu.Unlock()
217	}
