226	func profileSnapshotServiceCacheKey(svc agentlib.FizeauService) string {
227		t := reflect.TypeOf(svc)
228		if t == nil {
229			return ""
230		}
231		v := reflect.ValueOf(svc)
232		switch v.Kind() {
233		case reflect.Chan, reflect.Func, reflect.Map, reflect.Pointer, reflect.Slice, reflect.UnsafePointer:
234			if v.IsNil() {
235				return ""
236			}
237			return fmt.Sprintf("service:%s:%x", t.String(), v.Pointer())
238		default:
239			if t.Comparable() {
240				return fmt.Sprintf("service:%s:%v", t.String(), svc)
241			}
242		}
243		return ""
244	}
