253	// SelectCheapestProfile returns the lowest-power profile band that has at least
254	// one available, auto-routable model.
255	func SelectCheapestProfile(snap ProfileSnapshot) string {
256		profiles := satisfiableProfiles(snap, 0)
257		sort.SliceStable(profiles, func(i, j int) bool {
258			left, right := profiles[i], profiles[j]
259			if profileMaxForSort(left) != profileMaxForSort(right) {
260				return profileMaxForSort(left) < profileMaxForSort(right)
261			}
262			if left.MinPower != right.MinPower {
263				return left.MinPower < right.MinPower
264			}
265			return preferProfile(left, right)
266		})
267		if len(profiles) == 0 {
268			return ""
269		}
270		return profiles[0].Name
271	}
