320	// SelectImplementationProfile chooses an opaque Fizeau profile name for
321	// implementation work. It ranks by policy metadata, not by hard-coded policy
322	// names. Ordinary auto-routing avoids profiles with hard requirements (for
323	// example local-only/no-remote policy requirements) unless DDx has an explicit
324	// matching intent; explicit --profile remains a raw passthrough handled by
325	// Fizeau.
326	func SelectImplementationProfile(snap ProfileSnapshot, powerClass escalation.PowerClass) ImplementationProfileSelection {
327		return selectImplementationProfile(snap, powerClass, 0)
328	}
