338	func selectImplementationProfile(snap ProfileSnapshot, powerClass escalation.PowerClass, floor int) ImplementationProfileSelection {
339		profiles := implementationCandidateProfiles(snap, floor)
340		if len(profiles) == 0 {
341			return ImplementationProfileSelection{}
342		}
343		selected, note := chooseImplementationCandidate(snap, profiles, powerClass, floor)
344		return ImplementationProfileSelection{
345			Name:     selected.Name,
346			MinPower: selected.MinPower,
347			Degraded: note != "",
348			Note:     note,
349		}
350	}
