352	func implementationCandidateProfiles(snap ProfileSnapshot, floor int) []agentlib.PolicyInfo {
353		profiles := satisfiableProfiles(snap, 0)
354		out := make([]agentlib.PolicyInfo, 0, len(profiles))
355		for _, profile := range profiles {
356			if hasHardPolicyRequirement(profile) {
357				continue
358			}
359			if floor > 0 && profileMaxForSort(profile) < floor {
360				continue
361			}
362			out = append(out, profile)
363		}
364		sort.SliceStable(out, func(i, j int) bool {
365			return implementationProfileLess(snap, out[i], out[j])
366		})
367		return out
368	}
