370	func chooseImplementationCandidate(snap ProfileSnapshot, profiles []agentlib.PolicyInfo, powerClass escalation.PowerClass, floor int) (agentlib.PolicyInfo, string) {
371		if floor > 0 && powerClass != escalation.PowerSmart {
372			return profiles[0], ""
373		}
374		switch powerClass {
375		case escalation.PowerSmart:
376			return profiles[len(profiles)-1], ""
377		case escalation.PowerStandard:
378			if selected, note, ok := standardProfileSelection(snap, profiles); ok {
379				return selected, note
380			}
381			return profiles[0], "medium profile unavailable; using only available profile"
382		case escalation.PowerCheap, "":
383			return profiles[0], ""
384		default:
385			return profiles[0], ""
386		}
387	}
