389	func firstBandAboveLowest(profiles []agentlib.PolicyInfo) (agentlib.PolicyInfo, bool) {
390		if len(profiles) <= 1 {
391			return agentlib.PolicyInfo{}, false
392		}
393		lowest := profiles[0]
394		for _, profile := range profiles[1:] {
395			if profile.MinPower > lowest.MinPower || profileMaxForSort(profile) > profileMaxForSort(lowest) {
396				return profile, true
397			}
398		}
399		return agentlib.PolicyInfo{}, false
400	}
