402	// standardProfileSelection prefers the configured medium band. Model discovery
403	// is advisory and may be stale relative to Fizeau's live route resolver, so a
404	// standard-powerClass implementation must not silently downgrade to the weakest
405	// policy just because the cached model snapshot does not currently contain a
406	// live medium-band candidate.
407	func standardProfileSelection(snap ProfileSnapshot, available []agentlib.PolicyInfo) (agentlib.PolicyInfo, string, bool) {
408		if len(available) == 0 {
409			return agentlib.PolicyInfo{}, "", false
410		}
411		desired, ok := desiredStandardProfile(snap)
412		if !ok {
413			if selected, ok := firstBandAboveLowest(available); ok {
414				return selected, "", true
415			}
416			return agentlib.PolicyInfo{}, "", false
417		}
418		for _, profile := range available {
419			if profile.Name == desired.Name {
420				return profile, "", true
421			}
422		}
423		return desired, "medium profile absent from live model snapshot; requesting medium policy", true
424	}
