426	func desiredStandardProfile(snap ProfileSnapshot) (agentlib.PolicyInfo, bool) {
427		profiles := make([]agentlib.PolicyInfo, 0, len(snap.Profiles))
428		for _, profile := range snap.Profiles {
429			if profile.Name == "" || hasHardPolicyRequirement(profile) {
430				continue
431			}
432			if profile.MinPower == 0 && profile.MaxPower == 0 {
433				continue
434			}
435			profiles = append(profiles, profile)
436		}
437		sort.SliceStable(profiles, func(i, j int) bool {
438			if profileMaxForSort(profiles[i]) != profileMaxForSort(profiles[j]) {
439				return profileMaxForSort(profiles[i]) < profileMaxForSort(profiles[j])
440			}
441			if profiles[i].MinPower != profiles[j].MinPower {
442				return profiles[i].MinPower < profiles[j].MinPower
443			}
444			return profiles[i].Name < profiles[j].Name
445		})
446		return firstBandAboveLowest(profiles)
447	}
