458	func satisfiableProfiles(snap ProfileSnapshot, floor int) []agentlib.PolicyInfo {
459		out := make([]agentlib.PolicyInfo, 0, len(snap.Profiles))
460		for _, profile := range snap.Profiles {
461			if profile.Name == "" {
462				continue
463			}
464			if hasHardPolicyRequirement(profile) {
465				continue
466			}
467			if profile.MinPower == 0 && profile.MaxPower == 0 {
468				continue
469			}
470			if floor > 0 && profile.MinPower < floor {
471				continue
472			}
473			if profileHasAvailableModel(profile, snap.Models) {
474				out = append(out, profile)
475			}
476		}
477		return out
478	}
