480	func profileHasAvailableModel(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) bool {
481		if len(models) == 0 {
482			return true
483		}
484		for _, model := range models {
485			if !model.Available || !model.AutoRoutable || model.ExactPinOnly {
486				continue
487			}
488			if profile.MinPower > 0 && model.Power < profile.MinPower {
489				continue
490			}
491			if profile.MaxPower > 0 && model.Power > profile.MaxPower {
492				continue
493			}
494			return true
495		}
496		return false
497	}
