499	func implementationProfileLess(snap ProfileSnapshot, left, right agentlib.PolicyInfo) bool {
500		if profileMaxForSort(left) != profileMaxForSort(right) {
501			return profileMaxForSort(left) < profileMaxForSort(right)
502		}
503		if left.MinPower != right.MinPower {
504			return left.MinPower < right.MinPower
505		}
506		leftCost, leftCostOK := profileBestCost(left, snap.Models)
507		rightCost, rightCostOK := profileBestCost(right, snap.Models)
508		if leftCostOK != rightCostOK {
509			return leftCostOK
510		}
511		if leftCostOK && rightCostOK && leftCost != rightCost {
512			return leftCost < rightCost
513		}
514		leftSpeed, leftSpeedOK := profileBestSpeed(left, snap.Models)
515		rightSpeed, rightSpeedOK := profileBestSpeed(right, snap.Models)
516		if leftSpeedOK != rightSpeedOK {
517			return leftSpeedOK
518		}
519		if leftSpeedOK && rightSpeedOK && leftSpeed != rightSpeed {
520			return leftSpeed > rightSpeed
521		}
522		return left.Name < right.Name
523	}
