525	func profileBestCost(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) (float64, bool) {
526		best := 0.0
527		ok := false
528		for _, model := range models {
529			if !modelFitsProfile(profile, model) {
530				continue
531			}
532			cost := model.Cost.InputPerMTok + model.Cost.OutputPerMTok
533			if !ok || cost < best {
534				best = cost
535				ok = true
536			}
537		}
538		return best, ok
539	}
540	
541	func profileBestSpeed(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) (float64, bool) {
542		best := 0.0
543		ok := false
544		for _, model := range models {
545			if !modelFitsProfile(profile, model) {
546				continue
547			}
548			speed := model.PerfSignal.SpeedTokensPerSec
549			if speed <= 0 {
550				continue
551			}
552			if !ok || speed > best {
553				best = speed
554				ok = true
555			}
556		}
557		return best, ok
558	}
559	
560	func modelFitsProfile(profile agentlib.PolicyInfo, model agentlib.ModelInfo) bool {
561		if !model.Available || !model.AutoRoutable || model.ExactPinOnly {
562			return false
563		}
564		if profile.MinPower > 0 && model.Power < profile.MinPower {
565			return false
566		}
567		if profile.MaxPower > 0 && model.Power > profile.MaxPower {
568			return false
569		}
570		return true
571	}
