573	func profileMaxForSort(profile agentlib.PolicyInfo) int {
574		if profile.MaxPower == 0 {
575			return math.MaxInt
576		}
577		return profile.MaxPower
578	}
579	
580	func preferProfile(left, right agentlib.PolicyInfo) bool {
581		return left.Name < right.Name
582	}
