584	func selectProfileForDispatch(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, selector func(ProfileSnapshot) string) string {
585		if selector == nil || runner != nil {
586			return ""
587		}
588		blocking := svc != nil
589		selectedSvc := svc
590		if selectedSvc == nil {
591			factory := serviceRunFactory
592			if factory == nil {
593				factory = NewServiceFromWorkDir
594			}
595			built, err := factory(projectRoot)
596			if err != nil {
597				return ""
598			}
599			selectedSvc = built
600		}
601		key := profileSnapshotProjectCacheKey(projectRoot, selectedSvc)
602		if snap, ok := cachedProfileSnapshot(key); ok {
603			startProfileSnapshotRefresh(key, selectedSvc)
604			return selector(snap)
605		}
606		if blocking {
607			snap, err := loadProfileSnapshot(ctx, key, selectedSvc)
608			if err != nil {
609				return ""
610			}
611			return selector(snap)
612		}
613		if coldCtx, cancel := profileSnapshotColdLoadContext(ctx); coldCtx != nil {
614			defer cancel()
615			snap, err := loadProfilePolicySnapshot(coldCtx, key, selectedSvc)
616			if err == nil {
617				startProfileSnapshotRefresh(key, selectedSvc)
618				return selector(snap)
619			}
620		}
621		startProfileSnapshotRefresh(key, selectedSvc)
622		return ""
623	}
