625	func loadProfilePolicySnapshot(ctx context.Context, key string, svc agentlib.FizeauService) (ProfileSnapshot, error) {
626		profiles, err := svc.ListPolicies(ctx)
627		if err != nil {
628			return ProfileSnapshot{}, err
629		}
630		snap := ProfileSnapshot{Profiles: append([]agentlib.PolicyInfo(nil), profiles...)}
631		if key != "" {
632			profileSnapshotCacheMu.Lock()
633			profileSnapshotCache[key] = profileSnapshotCacheEntry{snap: cloneProfileSnapshot(snap), loadedAt: profileSnapshotNow()}
634			profileSnapshotCacheMu.Unlock()
635		}
636		return snap, nil
637	}
