639	func profileSnapshotColdLoadContext(parent context.Context) (context.Context, context.CancelFunc) {
640		if profileSnapshotColdLoadTimeout <= 0 {
641			if parent == nil {
642				return context.Background(), func() {}
643			}
644			return parent, func() {}
645		}
646		if parent == nil {
647			parent = context.Background()
648		}
649		return context.WithTimeout(parent, profileSnapshotColdLoadTimeout)
650	}
