59	// resolveService returns a FizeauService for workDir, using the test-injected
60	// factory when set and the production NewServiceFromWorkDir otherwise. All
61	// internal callers (RunWithConfigViaService, ValidateForExecuteLoopViaService,
62	// etc.) must go through this helper so test stubs installed via
63	// SetServiceRunFactory are honored everywhere.
64	func resolveService(workDir string) (agentlib.FizeauService, error) {
65		factory := serviceRunFactory
