72	// appendProviderTimeoutHint appends a configuration override hint to errMsg
73	// when it indicates a provider request timeout fired. Helps operators find
74	// the knob to adjust (AC4 of ddx-2c63bb95).
75	func appendProviderTimeoutHint(errMsg string, providerTimeout time.Duration) string {
76		if errMsg == "" || !strings.Contains(errMsg, "provider request timeout") {
77			return errMsg
78		}
79		return errMsg + fmt.Sprintf(
80			"; request_timeout=%s exceeded — override via"+
81				" agent.endpoints.<name>.request_timeout_seconds in .ddx/config.yaml"+
82				" or pass --request-timeout DURATION to execute-bead/work",
83			providerTimeout.Round(time.Second),
84		)
85	}
