87	// RunWithConfigViaService dispatches a single agent invocation through the
88	// agent service. It takes a sealed ResolvedConfig (durable knobs) and an
89	// AgentRunRuntime (per-invocation plumbing/intent), and is the SD-024
90	// successor to the retired RunViaService/RunViaServiceWith entry points.
91	//
92	// The virtual and script harnesses route through a DDx-owned Runner path,
93	// not the upstream service. These are not "carve-outs pending migration" —
94	// they are different products from upstream's same-named stubs. DDx's
95	// virtual is a content-addressed record/replay dictionary keyed by
96	// PromptHash; upstream's is a unit-test stub where callers stuff
97	// virtual.response into Metadata. DDx's script reads a filesystem directive
98	// file; upstream does not model this at all.
99	func RunWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
100		if ctx == nil {
101			ctx = context.Background()
102		}
103	
104		harness := rcfg.Passthrough().Harness
105	
106		effectivePerms := runtime.PermissionsOverride
107		if effectivePerms == "" {
108			effectivePerms = rcfg.Permissions()
109		}
110		if err := ValidateReadOnlyReviewerDispatch(harness, effectivePerms); err != nil {
111			return nil, err
112		}
113	
114		if harness == "virtual" || harness == "script" {
115			sessionLogDir := runtime.SessionLogDirOverride
116			if sessionLogDir == "" {
117				sessionLogDir = rcfg.SessionLogDir()
118			}
119			cfg := Config{SessionLogDir: ResolveLogDir(workDir, "")}
120			r := NewRunner(cfg)
121			r.WorkDir = workDir
122			return r.runInternal(RunArgs{
123				Context:       ctx,
124				Harness:       rcfg.Harness(),
125				Prompt:        runtime.Prompt,
126				PromptFile:    runtime.PromptFile,
127				PromptSource:  runtime.PromptSource,
128				Correlation:   runtime.Correlation,
129				Model:         rcfg.Model(),
130				Provider:      rcfg.Provider(),
131				Effort:        rcfg.Effort(),
132				Timeout:       rcfg.Timeout(),
133				WallClock:     rcfg.WallClock(),
134				WorkDir:       runtime.WorkDir,
135				Permissions:   rcfg.Permissions(),
136				SessionLogDir: sessionLogDir,
137				Env:           runtime.Env,
138			})
139		}
140	
141		svc, err := resolveService(workDir)
142		if err != nil {
143			return nil, fmt.Errorf("agent: build service: %w", err)
144		}
145		return executeOnService(ctx, svc, workDir, rcfg, runtime)
146	}
147	
148	// executeOnService dispatches against a pre-built svc using the durable
149	// knobs from rcfg and per-invocation plumbing from runtime, then records
150	// one session-index row. It is the inlined replacement for the retired
151	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
152	func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
153		if svc == nil {
154			return nil, fmt.Errorf("agent: nil service")
155		}
156		if ctx == nil {
157			ctx = context.Background()
158		}
159	
160		promptText := runtime.Prompt
161		if runtime.PromptFile != "" {
162			data, err := readPromptFileBounded(runtime.PromptFile)
163			if err != nil {
164				return nil, fmt.Errorf("agent: read prompt file: %w", err)
165			}
166			promptText = string(data)
167		}
168		if promptText == "" {
169			return nil, fmt.Errorf("agent: prompt is required")
170		}
171	
172		wd := runtime.WorkDir
173		if wd == "" {
174			wd = workDir
175		}
176		if wd == "" {
177			wd, _ = os.Getwd()
178		}
179	
180		idle := rcfg.Timeout()
181		if idle <= 0 {
182			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
183		}
184		wall := rcfg.WallClock()
185		if wall <= 0 {
186			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
187		}
188	
189		sessionLogDir := runtime.SessionLogDirOverride
190		if sessionLogDir == "" {
191			sessionLogDir = rcfg.SessionLogDir()
192		}
193		if sessionLogDir == "" {
194			sessionLogDir = ResolveLogDir(workDir, "")
195		}
196	
197		pt := rcfg.Passthrough()
198	
199		harness := runtime.HarnessOverride
200		if harness == "" && !runtime.ClearRoutingPins {
201			harness = pt.Harness
202		}
203	
204		model := runtime.ModelOverride
205		if model == "" && !runtime.ClearRoutingPins {
206			model = pt.Model
207		}
208	
209		provider := runtime.ProviderOverride
210		if provider == "" && !runtime.ClearRoutingPins {
211			provider = pt.Provider
212		}
213		if runtime.ClearRoutingPins && runtime.ProviderOverride == "" {
214			provider = ""
215		}
216	
217		profile := runtime.ProfileOverride
218		if profile == "" && !runtime.ClearProfile {
219			profile = rcfg.Profile()
220		}
221	
222		permissions := runtime.PermissionsOverride
223		if permissions == "" {
224			permissions = rcfg.Permissions()
225		}
226	
227		providerTimeout := ResolveProviderRequestTimeout(workDir, provider, model, rcfg.ProviderRequestTimeout())
228	
229		minPower := rcfg.MinPower()
230		if runtime.MinPowerOverride > 0 {
231			minPower = runtime.MinPowerOverride
232		}
233		if runtime.ClearMinPower {
234			minPower = 0
235		}
236		maxPower := rcfg.MaxPower()
237		if runtime.ClearMaxPower {
238			maxPower = 0
239		}
240		if minPower > 0 && maxPower > 0 && minPower >= maxPower {
241			return nil, fmt.Errorf("agent: invalid power bounds: min_power=%d must be less than max_power=%d", minPower, maxPower)
242		}
243	
244		req := agentlib.ServiceExecuteRequest{
245			Prompt:                promptText,
246			Model:                 model,
247			Policy:                profile,
248			Provider:              provider,
249			Harness:               fizeauHarness(harness),
250			Reasoning:             agentlib.Reasoning(rcfg.Effort()),
251			Permissions:           permissions,
252			WorkDir:               wd,
253			Timeout:               wall,
254			IdleTimeout:           idle,
255			ProviderTimeout:       providerTimeout,
256			SessionLogDir:         sessionLogDir,
257			Metadata:              metadataWithEnv(runtime.Correlation, runtime.Env),
258			Role:                  runtime.Role,
259			CorrelationID:         runtime.CorrelationID,
260			MinPower:              minPower,
261			MaxPower:              maxPower,
262			EstimatedPromptTokens: firstPositiveInt(runtime.EstimatedPromptTokens, estimatePromptTokens(promptText)),
263			RequiresTools:         runtime.RequiresTools,
264		}
265		seedRecentRouteAttemptsFromTracker(ctx, svc, workDir, time.Now().UTC())
266	
267		cancelCtx, cancel := context.WithCancel(ctx)
268		defer cancel()
269	
270		// When Harness is set and Model is empty, fizeau routes within the harness's
271		// eligible models using Profile/MinPower as the routing constraint. This is the
272		// well-formed request shape for profile-driven dispatch without an explicit model.
273		// fizeau returns ErrHarnessModelIncompatible (typed, non-nil) on pre-dispatch
274		// errors and a failed final event for post-dispatch errors.
275		start := time.Now().UTC()
276		events, err := svc.Execute(cancelCtx, req)
277		if err != nil {
278			return nil, fmt.Errorf("agent: execute: %w", err)
279		}
280	
281		workPhase := strings.TrimSpace(runtime.WorkLogPhase)
282		if workPhase == "" {
283			workPhase = "do"
284		}
285		renderer := NewWorkLogRenderer(WorkLogRendererOptions{
286			CurrentBeadID: runtime.Correlation["bead_id"],
287			WorkPhase:     workPhase,
288		})
289		watchdog := &drainWatchdog{
290			cancel:          cancel,
291			idleTimeout:     idle,
292			toolCallTimeout: time.Duration(ToolCallTimeout) * time.Millisecond,
293		}
294		final, routing, _ := drainServiceEventsWithRenderer(events, runtime.Output, renderer, watchdog)
295		finishedAt := time.Now().UTC()
296		elapsed := finishedAt.Sub(start)
297	
298		result := &Result{
299			Harness:    fizeauHarness(harness),
300			Model:      model,
301			DurationMS: int(elapsed.Milliseconds()),
302		}
303		if routing != nil {
304			result.Provider = routing.Provider
305			if routing.Model != "" {
306				result.Model = routing.Model
307			}
308			if routing.Harness != "" {
309				result.Harness = routing.Harness
310			}
311			if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
312				result.PredictedPower = power
313				result.PredictedSpeedTPS = speed
314				result.PredictedCostUSDPer1kTokens = cost
315				result.PredictedCostSource = source
316			}
317		}
318		if final != nil {
319			// Normalized final text from the upstream harness (agent-32e8ff5e);
320			// reviewer verdict extraction now parses this instead of raw stream
321			// frames (ddx-7bc0c8d5).
322			result.Output = final.FinalText
323			if final.Usage != nil {
324				// v0.9.1: Usage fields became *int (nullable).
325				if final.Usage.InputTokens != nil {
326					result.InputTokens = *final.Usage.InputTokens
327				}
328				if final.Usage.OutputTokens != nil {
329					result.OutputTokens = *final.Usage.OutputTokens
330				}
331				if final.Usage.CacheReadTokens != nil {
332					result.CachedTokens = *final.Usage.CacheReadTokens
333				}
334				if final.Usage.TotalTokens != nil {
335					result.Tokens = *final.Usage.TotalTokens
336				}
337			}
338			if final.CostUSD > 0 {
339				result.CostUSD = final.CostUSD
340			}
341			result.ExitCode = final.ExitCode
342			result.Error = final.Error
343			if final.RoutingActual != nil {
344				if result.Provider == "" {
345					result.Provider = final.RoutingActual.Provider
346				}
347				if final.RoutingActual.Model != "" {
348					result.Model = final.RoutingActual.Model
349				}
350				if final.RoutingActual.Harness != "" {
351					result.Harness = final.RoutingActual.Harness
352				}
353				if final.RoutingActual.Power > 0 {
354					result.ActualPower = final.RoutingActual.Power
355				}
356			}
357			if final.SessionLogPath != "" {
358				result.AgentSessionID = final.SessionLogPath
359			}
360		}
361		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
362		normalizeServiceFinalExitCode(result)
363		recordServiceRouteAttempt(ctx, svc, result, elapsed, finishedAt)
364		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
365			Harness:     harness,
366			Model:       model,
367			Provider:    provider,
368			Effort:      rcfg.Effort(),
369			Correlation: runtime.Correlation,
370		}, result, start, finishedAt)
371		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
372		return result, nil
373	}
