392	func seedRecentRouteAttemptsFromTracker(ctx context.Context, svc agentlib.FizeauService, projectRoot string, now time.Time) {
393		if svc == nil || strings.TrimSpace(projectRoot) == "" {
394			return
395		}
396		store := bead.NewStore(ddxroot.JoinProject(projectRoot))
397		beads, err := store.List("", "", nil)
398		if err != nil {
399			return
400		}
401		cutoff := now.Add(-ProviderUnavailableCooldown)
402		seen := map[string]struct{}{}
403		for _, b := range beads {
404			for _, failed := range readFailedRoutes(b.Extra) {
405				at, _ := time.Parse(time.RFC3339, strings.TrimSpace(failed.At))
406				if at.IsZero() {
407					at = now
408				}
409				if at.Before(cutoff) || at.After(now.Add(time.Minute)) || strings.TrimSpace(failed.Provider) == "" {
410					continue
411				}
412				key := "\x00" + failed.Provider + "\x00" + failed.Model
413				if _, ok := seen[key]; ok {
414					continue
415				}
416				seen[key] = struct{}{}
417				// Rebase replayed failures to `now` so they survive fizeau's
418				// route-health TTL window. Historical tracker timestamps (minutes
419				// to ~15 min old) sit outside fizeau's default 30s cooldown and
420				// are dropped immediately by ActiveAttempts, leaving policy/default
421				// Execute routes free to re-pick the same failed provider. The
422				// tracker-side cutoff above (ProviderUnavailableCooldown) decides
423				// which failures are still worth replaying; once they pass that
424				// gate they are asserted active for fizeau's TTL counted from now.
425				_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
426					Provider:  failed.Provider,
427					Model:     failed.Model,
428					Status:    "failed",
429					Reason:    FailureModeProviderConnectivity,
430					Error:     FailureModeProviderConnectivity,
431					Timestamp: now,
432				})
433			}
434			events, err := store.Events(b.ID)
435			if err != nil {
436				continue
437			}
438			for _, ev := range events {
439				if ev.Kind != "route-failure" || ev.CreatedAt.Before(cutoff) || ev.CreatedAt.After(now.Add(time.Minute)) {
440					continue
441				}
442				var body map[string]any
443				if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
444					continue
445				}
446				if strings.TrimSpace(fmt.Sprint(body["outcome_reason"])) != FailureModeProviderConnectivity {
447					continue
448				}
449				provider := strings.TrimSpace(fmt.Sprint(body["provider"]))
450				if provider == "" || provider == "<nil>" {
451					continue
452				}
453				harness := strings.TrimSpace(fmt.Sprint(body["harness"]))
454				model := strings.TrimSpace(fmt.Sprint(body["model"]))
455				key := harness + "\x00" + provider + "\x00" + model
456				if _, ok := seen[key]; ok {
457					continue
458				}
459				seen[key] = struct{}{}
460				_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
461					Harness:   harness,
462					Provider:  provider,
463					Model:     model,
464					Status:    "failed",
465					Reason:    FailureModeProviderConnectivity,
466					Error:     strings.TrimSpace(fmt.Sprint(body["error"])),
467					Timestamp: now,
468				})
469			}
470		}
471	}
