473	func recordServiceRouteAttempt(ctx context.Context, svc agentlib.FizeauService, result *Result, elapsed time.Duration, finishedAt time.Time) {
474		if svc == nil || result == nil || strings.TrimSpace(result.Provider) == "" {
475			return
476		}
477		status := "success"
478		reason := "success"
479		if result.ExitCode != 0 || strings.TrimSpace(result.Error) != "" {
480			status = "failed"
481			reason = "execution_failed"
482			if strings.TrimSpace(result.Error) != "" {
483				reason = "provider_error"
484			}
485		}
486		_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
487			Harness:   result.Harness,
488			Provider:  result.Provider,
489			Model:     result.Model,
490			Status:    status,
491			Reason:    reason,
492			Error:     result.Error,
493			Duration:  elapsed,
494			Timestamp: finishedAt,
495		})
496	}
