498	func metadataWithEnv(metadata, env map[string]string) map[string]string {
499		if len(metadata) == 0 && len(env) == 0 {
500			return nil
501		}
502		out := make(map[string]string, len(metadata)+len(env))
503		for k, v := range metadata {
504			out[k] = v
505		}
506		for k, v := range env {
507			out[k] = v
508		}
509		return out
510	}
