521	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
522	// querying the service's ListHarnesses and (best-effort) the harness registry.
523	// It is the production replacement for Runner.Capabilities.
524	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
525		if ctx == nil {
526			ctx = context.Background()
527		}
528		svc, err := resolveService(workDir)
529		if err != nil {
530			return nil, fmt.Errorf("agent: build service: %w", err)
531		}
532		infos, err := svc.ListHarnesses(ctx)
533		if err != nil {
534			return nil, fmt.Errorf("agent: list harnesses: %w", err)
535		}
536		var info *agentlib.HarnessInfo
537		for i := range infos {
538			if infos[i].Name == harnessName {
539				info = &infos[i]
540				break
541			}
542		}
543		if info == nil {
544			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
545		}
546	
547		// Pull binary and reasoning-level metadata from the local registry — the
548		// service does not expose these directly today.
549		registry := newHarnessRegistry()
550		harness, _ := registry.Get(harnessName)
551	
552		caps := &HarnessCapabilities{
553			Harness:             info.Name,
554			Available:           info.Available,
555			Binary:              harness.Binary,
556			Path:                info.Path,
557			Surface:             harness.Surface,
558			CostClass:           info.CostClass,
559			IsLocal:             info.CostClass == "local",
560			ExactPinSupport:     info.ExactPinSupport,
561			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
562			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
563		}
564		if len(info.SupportedReasoning) > 0 {
565			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
566		} else if len(harness.ReasoningLevels) > 0 {
567			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
568		}
569	
570		if harness.DefaultModel != "" {
571			caps.Model = harness.DefaultModel
572			caps.Models = []string{harness.DefaultModel}
573		}
574	
575		return caps, nil
576	}
