578	// TestProviderConnectivityViaService runs a HealthCheck against the named
579	// harness and translates the result into a ProviderStatus. It is the
580	// production replacement for Runner.TestProviderConnectivity.
581	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
582		status := ProviderStatus{Reachable: false}
583		if ctx == nil {
584			ctx = context.Background()
585		}
586		if harnessName == "virtual" || harnessName == "agent" {
587			status.Reachable = true
588			status.CreditsOK = true
589			return status
590		}
591		svc, err := resolveService(workDir)
592		if err != nil {
593			status.Error = err.Error()
594			return status
595		}
596		if timeout > 0 {
597			var cancel context.CancelFunc
598			ctx, cancel = context.WithTimeout(ctx, timeout)
599			defer cancel()
600		}
601		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
602			errStr := strings.ToLower(err.Error())
603			status.Error = err.Error()
604			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
605				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
606				status.CreditsOK = false
607			}
608			return status
609		}
610		status.Reachable = true
611		status.CreditsOK = true
612		return status
613	}
